type StreamResult<T> = Pin<Box<dyn Stream<Item = Result<T, Status>> + Send + 'static>>;
pub const DEFAULT_RESPONSE_TIMEOUT_SECS: u64 = 300;

/// 64 MiB — leaves headroom for multimodal inputs and OpenAI JSON pass-through bodies,
